import json
import urllib.parse
import urllib.request
import re
from typing import Dict, Any, List

# Allowlist of permitted domains for enrichment URLs
ALLOWED_DOMAINS = [
    'api.trusted-partner.com',
    'enrichment.internal-service.com',
    'data.approved-vendor.com'
]

# Maximum number of enrichment URLs to process
MAX_ENRICH_URLS = 3

# Timeout for HTTP requests (in seconds)
REQUEST_TIMEOUT = 2

# Maximum response size (in bytes)
MAX_RESPONSE_SIZE = 10240  # 10KB

def validate_url(url: str) -> bool:
    """
    Validate URL against security requirements.
    Returns True if URL is safe to fetch, False otherwise.
    """
    try:
        parsed = urllib.parse.urlparse(url)
        
        # Must use HTTPS
        if parsed.scheme != 'https':
            return False
        
        # Must have a valid hostname
        if not parsed.hostname:
            return False
        
        # Check against allowlist
        if parsed.hostname not in ALLOWED_DOMAINS:
            return False
        
        # Prevent SSRF to internal/private IPs
        # Block localhost, private networks, link-local
        hostname = parsed.hostname.lower()
        if hostname in ['localhost', '127.0.0.1', '::1']:
            return False
        
        # Block private IP ranges (basic check)
        if hostname.startswith('10.') or hostname.startswith('192.168.') or hostname.startswith('172.'):
            return False
        
        # Block metadata endpoints
        if '169.254.169.254' in hostname:
            return False
        
        return True
        
    except Exception:
        return False

def sanitize_header_value(value: str) -> str:
    """
    Sanitize header values to prevent injection attacks.
    """
    # Remove control characters and limit length
    sanitized = re.sub(r'[\x00-\x1F\x7F]', '', value)
    return sanitized[:1024]  # Limit to 1KB

def fetch_enrichment_data(url: str) -> Dict[str, Any]:
    """
    Fetch data from validated URL with security controls.
    """
    try:
        req = urllib.request.Request(
            url,
            headers={
                'User-Agent': 'CloudFront-Edge-Enrichment/1.0',
                'Accept': 'application/json'
            }
        )
        
        with urllib.request.urlopen(req, timeout=REQUEST_TIMEOUT) as response:
            # Check response size
            content_length = response.headers.get('Content-Length')
            if content_length and int(content_length) > MAX_RESPONSE_SIZE:
                return {'error': 'Response too large'}
            
            # Read with size limit
            data = response.read(MAX_RESPONSE_SIZE)
            
            # Only accept JSON responses
            content_type = response.headers.get('Content-Type', '')
            if 'application/json' not in content_type:
                return {'error': 'Invalid content type'}
            
            return json.loads(data.decode('utf-8'))
            
    except urllib.error.HTTPError as e:
        return {'error': f'HTTP error: {e.code}'}
    except urllib.error.URLError:
        return {'error': 'URL error'}
    except json.JSONDecodeError:
        return {'error': 'Invalid JSON'}
    except Exception:
        return {'error': 'Fetch failed'}

def lambda_handler(event: Dict[str, Any], context: Any) -> Dict[str, Any]:
    """
    Lambda@Edge viewer request handler with secure data enrichment.
    """
    request = event['Records'][0]['cf']['request']
    headers = request['headers']
    
    # Extract and validate enrichment URLs
    enrich_urls: List[str] = []
    
    if 'x-enrich-url' in headers:
        for header in headers['x-enrich-url']:
            url = sanitize_header_value(header['value'])
            
            # Validate URL before adding
            if validate_url(url):
                enrich_urls.append(url)
                
                # Enforce maximum limit
                if len(enrich_urls) >= MAX_ENRICH_URLS:
                    break
    
    # Fetch enrichment data from validated URLs
    enrichment_data = {}
    for idx, url in enumerate(enrich_urls):
        data = fetch_enrichment_data(url)
        enrichment_data[f'source_{idx}'] = data
    
    # Add enrichment data to request headers (if any was fetched)
    if enrichment_data:
        # Serialize to JSON and encode
        enrichment_json = json.dumps(enrichment_data)
        
        # Limit total enrichment data size
        if len(enrichment_json) <= 8192:  # 8KB limit for headers
            # Add as custom header for origin
            request['headers']['x-enrichment-data'] = [{
                'key': 'X-Enrichment-Data',
                'value': enrichment_json
            }]
    
    # Remove the enrichment URL header before forwarding
    if 'x-enrich-url' in request['headers']:
        del request['headers']['x-enrich-url']
    
    return request